def smallest_interleaving(str1, str2):
    from itertools import product
    import heapq

    def interleaving(str1, str2, result):
        if not str1 and not str2:
            yield result
        if str1:
            yield from interleaving(str1[1:], str2, result + str1[0])
        if str2:
            yield from interleaving(str1, str2[1:], result + str2[0])

    return min(interleaving(str1, str2, ''))

def smallest_interleaving_heapq(str1, str2):
    import heapq

    queue = [(str1 + str2, '')]
    seen = set()
    result = None

    while queue:
        string, current = heapq.heappop(queue)
        if not string:
            result = current
            break
        for i, char in enumerate(string):
            new_string = string[:i] + string[i + 1:]
            new_current = current + char
            if (new_string, new_current) not in seen:
                seen.add((new_string, new_current))
                heapq.heappush(queue, (new_string, new_current))

    return result

def smallest_interleaving_builtin(str1, str2):
    import itertools

    perms = [''.join(p) for p in itertools.permutations(str1 + str2)]
    valid = [p for p in perms if sorted(p[:len(str1)]) == sorted(str1) and sorted(p[len(str1):]) == sorted(str2)]
    return min(valid) if valid else ''

