class Solution:
    def minSteps(self, s: str, t: str) -> int:
        count_s = {}
        count_t = {}

        for char in s:
            if char in count_s:
                count_s[char] += 1
            else:
                count_s[char] = 1

        for char in t:
            if char in count_t:
                count_t[char] += 1
            else:
                count_t[char] = 1

        steps = 0
        for char in count_s:
            if char in count_t:
                steps += max(0, count_s[char] - count_t[char])
            else:
                steps += count_s[char]

        return steps

    def minStepsAlt(self, s: str, t: str) -> int:
        count = [0] * 26
        for char in s:
            count[ord(char) - ord('a')] += 1
        for char in t:
            count[ord(char) - ord('a')] -= 1

        steps = 0
        for i in range(26):
            steps += abs(count[i])

        return steps // 2

