class Graph:
    def __init__(self, vertices):
        self.V = vertices
        self.graph = [[0 for column in range(vertices)] for row in range(vertices)]

    def is_valid(self, v, pos, path):
        if self.graph[path[pos-1]][v] == 0:
            return False

        if v == path[0]:
            return False

        for i in range(pos):
            if path[i] == v:
                return False

        return True

    def hamiltonian_cycle_util(self, path, pos):
        if pos == self.V:
            return self.graph[path[pos-1]][path[0]] == 1

        for v in range(1, self.V):
            if self.is_valid(v, pos, path) == True:
                path[pos] = v

                if self.hamiltonian_cycle_util(path, pos+1) == True:
                    return True

                path[pos] = -1

        return False

    def hamiltonian_cycle(self):
        path = [-1] * self.V
        path[0] = 0

        if not self.hamiltonian_cycle_util(path, 1):
            return None

        return path

def find_hamiltonian_cycle(graph):
    g1 = Graph(len(graph))
    for i in range(len(graph)):
        for j in range(len(graph)):
            if graph[i][j] != 0:
                g1.graph[i][j] = 1
    return g1.hamiltonian_cycle()

