def find_shortest_path(graph, start, end):
    queue = [(start, [start])]
    while queue:
        (node, path) = queue.pop(0)
        for next_node in graph[node]:
            if next_node not in path:
                if next_node == end:
                    return path + [next_node]
                else:
                    queue.append((next_node, path + [next_node]))
    return None

